patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 394dfca262e1..70103cc7b601 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -280,6 +280,19 @@ Instruction *InstCombinerImpl::foldSelectOpOp(SelectInst &SI, Instruction *TI,
        match(&SI, m_UMax(m_Value(), m_Value()))))
     return nullptr;

+  // Handle select of two selects with the same condition but swapped operands:
+  // select c2, (select c1, a, b), (select c1, b, a) -> select (c1 xor c2), b, a
+  Value *Cond1, *A, *B;
+  if (match(TI, m_Select(m_Value(Cond1), m_Value(A), m_Value(B))) &&
+      match(FI, m_OneUse(m_Select(m_Specific(Cond1), m_Specific(B),
+                                  m_Specific(A))))) {
+    // Types must match for XOR (e.g., scalar vs vector select conditions)
+    if (Cond1->getType() == SI.getCondition()->getType()) {
+      Value *Xor = Builder.CreateXor(SI.getCondition(), Cond1, "xor.");
+      return SelectInst::Create(Xor, B, A);
+    }
+  }
+
   // If this is a cast from the same type, merge.
   Value *Cond = SI.getCondition();
   Type *CondTy = Cond->getType();

