  // Don't break up min/max patterns. The hasOneUse checks below prevent that
  // for most cases, but vector min/max with bitcasts can be transformed. If the
  // one-use restrictions are eased for other patterns, we still don't want to
  // obfuscate min/max.
  if ((match(&SI, m_SMin(m_Value(), m_Value())) ||
       match(&SI, m_SMax(m_Value(), m_Value())) ||
       match(&SI, m_UMin(m_Value(), m_Value())) ||
       match(&SI, m_UMax(m_Value(), m_Value()))))
    return nullptr;

  Value *Cond = SI.getCondition();
  Type *CondTy = Cond->getType();

  // Handle select of two selects with the same condition but swapped operands:
  // select c2, (select c1, a, b), (select c1, b, a) -> select (c1 xor c2), b, a
  Value *Cond1, *A, *B;
  if (match(TI, m_Select(m_Value(Cond1), m_Value(A), m_Value(B))) &&
      match(FI, m_OneUse(m_Select(m_Specific(Cond1), m_Specific(B),
